import{_ as t,o as i,c as o,ag as r}from"./chunks/framework.CpPsmr6h.js";const p=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"docs/troubleshooting.md","filePath":"docs/troubleshooting.md","lastUpdated":1771868171000}'),a={name:"docs/troubleshooting.md"};function s(l,e,n,c,h,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><p>Use this page to diagnose common setup and connectivity issues.</p><h2 id="device-does-not-show-as-online" tabindex="-1">Device Does Not Show as Online <a class="header-anchor" href="#device-does-not-show-as-online" aria-label="Permalink to &quot;Device Does Not Show as Online&quot;">​</a></h2><p>Checklist:</p><ul><li>Confirm power is connected.</li><li>Confirm Ethernet is connected to an active router/switch port.</li><li>Wait 1-2 minutes after boot.</li><li>Refresh the console dashboard.</li></ul><p>If still offline, reboot the device once and recheck.</p><h2 id="domain-is-registered-but-not-reachable" tabindex="-1">Domain Is Registered but Not Reachable <a class="header-anchor" href="#domain-is-registered-but-not-reachable" aria-label="Permalink to &quot;Domain Is Registered but Not Reachable&quot;">​</a></h2><p>Checklist:</p><ul><li>Verify domain status in the console.</li><li>Confirm a route exists for that domain.</li><li>Confirm target service is running locally.</li><li>Confirm route points to correct host/port.</li></ul><h2 id="route-exists-but-service-returns-errors" tabindex="-1">Route Exists but Service Returns Errors <a class="header-anchor" href="#route-exists-but-service-returns-errors" aria-label="Permalink to &quot;Route Exists but Service Returns Errors&quot;">​</a></h2><p>Checklist:</p><ul><li>Test the service directly on local network first.</li><li>Confirm the correct protocol is selected (HTTP, HTTP/2, or TCP).</li><li>Check application logs for 4xx/5xx errors.</li><li>Confirm the service is bound to the expected interface/port.</li></ul><h2 id="https-or-certificate-issues" tabindex="-1">HTTPS or Certificate Issues <a class="header-anchor" href="#https-or-certificate-issues" aria-label="Permalink to &quot;HTTPS or Certificate Issues&quot;">​</a></h2><p>Checklist:</p><ul><li>Verify domain registration completed successfully.</li><li>Wait briefly for provisioning if setup is recent.</li><li>Retry from a private/incognito browser window.</li></ul><h2 id="intermittent-connection-problems" tabindex="-1">Intermittent Connection Problems <a class="header-anchor" href="#intermittent-connection-problems" aria-label="Permalink to &quot;Intermittent Connection Problems&quot;">​</a></h2><p>Checklist:</p><ul><li>Check local network stability.</li><li>Reduce frequent route changes during active testing.</li><li>Verify the local service is not restarting/crashing.</li></ul><h2 id="when-to-escalate" tabindex="-1">When to Escalate <a class="header-anchor" href="#when-to-escalate" aria-label="Permalink to &quot;When to Escalate&quot;">​</a></h2><p>Collect this information before contacting support:</p><ul><li>Device ID</li><li>Domain name</li><li>Route configuration summary</li><li>Approximate timestamp of failure</li><li>Relevant app/log error messages</li></ul>',21)])])}const m=t(a,[["render",s]]);export{p as __pageData,m as default};
